# ============================================================
# RUN OPTIMIZATION (Shown to user)
# ============================================================
def run_optimization():
    print(BANNER)
    print("\n" + "=" * 80)
    print(" " * 30 + "OPTIMIZATION IN PROGRESS")
    print("=" * 80 + "\n")
    
    total_steps = len(PROGRESS)
    for i, step in enumerate(PROGRESS, 1):
        progress = int((i / total_steps) * 100)
        bar = "█" * (progress // 2) + "░" * (50 - progress // 2)
        print(f"[{progress:3}%] [{bar}] {step}")
        time.sleep(random.uniform(0.3, 0.8))
    
    print("\n" + "=" * 80)
    print(" " * 28 + "OPTIMIZATION COMPLETE")
